        } else if (c === 'T') {
            originalLCT += originalLC;
        }
    }
    maxCount = originalLCT;

    // Precompute prefix L counts and suffix CT counts
    const prefixL = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixL[i + 1] = prefixL[i] + (s[i] === 'L' ? 1 : 0);
    }

    const suffixCT = new Array(n + 1).fill(0);
    let countC = 0;
    for (let i = n - 1; i >= 0; i--) {
        if (s[i] === 'T') {
            suffixCT[i] = suffixCT[i + 1] + countC;
        } else if (s[i] === 'C') {
            countC += prefixL[i];
