        const ccCount = originalLC + cCount;
        const cctCount = originalLCT + (suffixCT[pos] - suffixCT[n]);
        if (cctCount > maxCount) {
            maxCount = cctCount;
        }

        // Insert 'T'
        const tCount = 0;
        const tcCount = originalLC;
